prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId ?created WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(CONTAINS(STR(?origId), "262d9e9b8c224d918fe800cd2a454ddf") || CONTAINS(STR(?normId), "262d9e9b8c224d918fe800cd2a454ddf"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?defs ?participantCount ?taskCount ?gatewayCount ?flowCount WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?model tai:belongsTo ?org .

  ?defs a bboExt:Definitions .
  ?defs tai:belongsTo ?model .

  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  {
    SELECT ?choreo (COUNT(DISTINCT ?participant) AS ?participantCount) WHERE {
      ?participant a bboExt:Participant .
      ?participant tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?gateway) AS ?gatewayCount) WHERE {
      ?gateway a bboExt:ExclusiveGateway .
      ?gateway tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?flow) AS ?flowCount) WHERE {
      ?flow a bbo:SequenceFlow .
      ?flow tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
}
LIMIT 25
